import scala.collection.mutable

object Solution {
  private val depthCache = mutable.HashMap[Long, Int]()

  private def computeDepth(x: Long): Int = {
    if (x == 1) return 0
    depthCache.getOrElseUpdate(x, {
      var cnt = 0
      var n = x
      while (n != 0) {
        cnt += (n & 1).toInt
        n = n >> 1
      }
      1 + computeDepth(cnt)
    })
  }

  def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
    val depths = new Array[Int](nums.length)
    for (i <- nums.indices) {
      depths(i) = computeDepth(nums(i))
    }

    val answer = mutable.ArrayBuffer[Long]()
    for (query <- queries) {
      if (query(0) == 1) {
        val l = query(1).toInt
        val r = query(2).toInt
        val k = query(3).toInt
        var count = 0
        for (j <- l to r) {
          if (depths(j) == k) {
            count += 1
