import scala.collection.mutable

object Solution {
  private val depthCache = mutable.HashMap[Long, Int]()

  private def computeDepth(x: Long): Int = {
    if (x == 1) return 0
    depthCache.getOrElseUpdate(x, {
      val cnt = x.toBinaryString.count(_ == '1')
      1 + computeDepth(cnt)
    })
  }

  def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
    val depths = nums.map(computeDepth)
    val answer = mutable.ArrayBuffer[Long]()

    for (query <- queries) {
      if (query(0) == 1) {
        val l = query(1).toInt
        val r = query(2).toInt
        val k = query(3).toInt
        var count = 0
        for (j <- l to r) {
          if (depths(j) == k) count += 1
        }
        answer += count
      } else if (query(0) == 2) {
        val idx = query(1).toInt
        val newVal = query(2)
        depths(idx) = computeDepth(newVal)
      }
    }
    answer.toArray
  }
}
